div.script:
// ── Step navigation ────────────────────────────────────────
var _currentStep = 1;
var _totalSteps = 5;

function kycGoto(n) {
  document.getElementById('panel-' + _currentStep).classList.remove('active');
  document.getElementById('step-dot-' + _currentStep).classList.remove('active');
  if (n > _currentStep) {
    document.getElementById('step-dot-' + _currentStep).classList.add('done');
  } else {
    document.getElementById('step-dot-' + (_currentStep)).classList.remove('done');
  }
  _currentStep = n;
  document.getElementById('panel-' + n).classList.add('active');
  document.getElementById('step-dot-' + n).classList.add('active');
  window.scrollTo({ top: 0, behavior: 'smooth' });
  // Re-initialise the signature canvas when step 5 becomes visible
  // (the panel starts hidden so getBoundingClientRect was 0×0 at load time)
  if (n === 5 && window.SignaturePad) { window.SignaturePad.resizeCanvas(); }
}

function kycNext(step) { if (kycValidateStep(step)) kycGoto(step + 1); }
function kycPrev(step) { kycGoto(step - 1); }

// Per-step JS validation — returns true only if all checks pass
function kycValidateStep(step) {
  var ok = true;

  function showErr(el, msg) {
    var p = el.closest('.form-group') || el.parentElement;
    if (p) p.classList.add('has-error');
    var errEl = p ? p.querySelector('.err-msg') : null;
    if (errEl) { errEl.textContent = msg || 'This field is required.'; errEl.style.display = 'block'; }
    ok = false;
  }
  function clearErr(el) {
    var p = el.closest('.form-group') || el.parentElement;
    if (p) p.classList.remove('has-error');
    var errEl = p ? p.querySelector('.err-msg') : null;
    if (errEl) errEl.style.display = '';
  }
  function reqField(selector) {
    var el = document.querySelector('#panel-' + step + ' ' + selector);
    if (!el) return;
    var val = el.value ? el.value.trim() : '';
    if (!val) showErr(el); else clearErr(el);
  }

  if (step === 1) {
    reqField('[name="first_name"]');
    reqField('[name="last_name"]');
    reqField('[name="date_of_birth"]');
    reqField('[name="gender"]');
    reqField('[name="nationality_id"]');
    reqField('[name="phone"]');
    // Email must be verified
    var emailEl = document.getElementById('kyc_email');
    if (!_emailVerified) {
      if (emailEl) showErr(emailEl, 'Please verify your email address first.');
      ok = false;
    } else {
      if (emailEl && emailEl.value.trim()) clearErr(emailEl);
    }
  }

  if (step === 2) {
    reqField('[name="passport_number"]');
    reqField('[name="passport_expiry_date"]');
    // At least one ID document must be uploaded
    var passportFile = document.getElementById('file_passport');
    var eidFile = document.getElementById('file_eid');
    var hasPassport = passportFile && passportFile.files && passportFile.files.length > 0;
    var hasEid = eidFile && eidFile.files && eidFile.files.length > 0;
    var docErr = document.getElementById('id_doc_err');
    if (!hasPassport && !hasEid) {
      if (docErr) { docErr.style.display = 'block'; }
      ok = false;
    } else {
      if (docErr) docErr.style.display = 'none';
    }
  }

  if (step === 3) {
    reqField('[name="residential_address"]');
    reqField('[name="residential_city"]');
    reqField('[name="residential_country_id"]');
  }

  if (step === 4) {
    reqField('[name="employment_status"]');
    reqField('[name="purpose_of_transaction"]');
    reqField('[name="payment_method"]');
    reqField('[name="annual_income"]');
    // At least one source of funds checkbox
    var fundsChecked = document.querySelectorAll('#panel-4 [name="source_of_funds_ids"]:checked').length;
    var fundsGrid = document.querySelector('#panel-4 .check-grid');
    var fundsErrDiv = document.querySelector('#panel-4 .check-grid + * .consent-err, #panel-4 [class*="check-grid"]');
    if (fundsChecked === 0) {
      if (fundsGrid) fundsGrid.classList.add('has-error');
      var existingErr = document.getElementById('funds_err_msg');
      if (!existingErr) {
        var errDiv = document.createElement('div');
        errDiv.id = 'funds_err_msg';
        errDiv.style.cssText = 'color:var(--err,#dc2626);font-size:.75rem;margin-top:6px;';
        errDiv.textContent = 'Please select at least one source of funds.';
        if (fundsGrid) fundsGrid.parentNode.insertBefore(errDiv, fundsGrid.nextSibling);
      }
      ok = false;
    } else {
      if (fundsGrid) fundsGrid.classList.remove('has-error');
      var existingErr2 = document.getElementById('funds_err_msg');
      if (existingErr2) existingErr2.remove();
    }
  }

  if (step === 5) {
    reqField('[name="politically_exposed_person"]');
    // Consents
    ['consent_terms_conditions','consent_privacy_policy','consent_data_processing','consent_aml_kyc'].forEach(function(n) {
      var cb = document.querySelector('[name="' + n + '"]');
      if (cb && !cb.checked) {
        var item = cb.closest('.consent-item');
        if (item) item.classList.add('has-error');
        ok = false;
      } else if (cb) {
        var item = cb.closest('.consent-item');
        if (item) item.classList.remove('has-error');
      }
    });
  }

  if (!ok) window.scrollTo({ top: 0, behavior: 'smooth' });
  return ok;
}

// Track file uploads and clear ID doc error when a file is chosen
function kycUpdateDocBadge() {
  var passportFile = document.getElementById('file_passport');
  var eidFile = document.getElementById('file_eid');
  var hasPassport = passportFile && passportFile.files && passportFile.files.length > 0;
  var hasEid = eidFile && eidFile.files && eidFile.files.length > 0;
  var docErr = document.getElementById('id_doc_err');
  if ((hasPassport || hasEid) && docErr) docErr.style.display = 'none';
}

// ── PEP toggle ──────────────────────────────────────────────
function togglePEP(val) {
  var wrap = document.getElementById('pep_details_wrap');
  wrap.style.display = (val && val !== 'no') ? 'flex' : 'none';
  wrap.style.flexDirection = 'column';
}
// Init on page load if coming back with values
(function(){ togglePEP(document.getElementById('pep_select') ? document.getElementById('pep_select').value : ''); })();

// ── File name display ───────────────────────────────────────
function showFileName(input, labelId) {
  var el = document.getElementById(labelId);
  if (el && input.files.length) {
    el.textContent = '✓ ' + input.files[0].name;
    el.style.display = 'block';
  }
}

// ── Submit: capture signature then submit ───────────────────
function kycSubmit(e) {
  if (window.SignaturePad) {
    if (!window.SignaturePad.validate()) {
      e.preventDefault();
      return false;
    }
  }
  var btn = document.getElementById('submit_kyc_form');
  if (btn) { btn.disabled = true; btn.textContent = 'Submitting…'; }
  return true;
}

// ── OTP email verification ──────────────────────────────────
var _emailVerified = false;
var _csrfToken = document.querySelector('[name=csrf_token]').value;

function kycSendOtp(resend) {
  var email = document.getElementById('kyc_email').value.trim();
  if (!email || !email.includes('@')) {
    alert('Please enter a valid email address first.');
    return;
  }
  var btn = document.getElementById('btn_send_otp');
  btn.disabled = true; btn.textContent = 'Sending…';

  fetch('/contact/kyc/send-otp', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({jsonrpc:'2.0',method:'call',id:1,
      params:{email: email}})
  })
  .then(r => r.json())
  .then(data => {
    var res = data.result || {};
    var msg = document.getElementById('otp_msg');
    if (res.success) {
      document.getElementById('otp_row').style.display = 'block';
      document.getElementById('kyc_email').readOnly = true;
      msg.style.color = '#059669';
      msg.textContent = '📩 Code sent to ' + email + '. Check your inbox (and spam folder).';
      btn.textContent = 'Resend';
      btn.disabled = false;
    } else {
      msg.style.color = '#dc2626';
      msg.textContent = res.error || 'Failed to send code.';
      btn.textContent = 'Send Code';
      btn.disabled = false;
      document.getElementById('otp_row').style.display = 'block';
    }
  })
  .catch(() => {
    btn.textContent = 'Send Code'; btn.disabled = false;
    alert('Network error. Please try again.');
  });
}

function kycVerifyOtp() {
  var email = document.getElementById('kyc_email').value.trim();
  var otp   = document.getElementById('kyc_otp_input').value.trim();
  var msg   = document.getElementById('otp_msg');
  if (otp.length !== 6) { msg.style.color='#dc2626'; msg.textContent='Enter the 6-digit code.'; return; }

  fetch('/contact/kyc/verify-otp', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({jsonrpc:'2.0',method:'call',id:2,
      params:{email: email, otp: otp}})
  })
  .then(r => r.json())
  .then(data => {
    var res = data.result || {};
    if (res.success) {
      _emailVerified = true;
      document.getElementById('otp_row').style.display = 'none';
      document.getElementById('btn_send_otp').style.display = 'none';
      document.getElementById('email_verified_badge').style.display = 'block';
      document.getElementById('kyc_otp_input').value = '';
    } else {
      msg.style.color = '#dc2626';
      msg.textContent = res.error || 'Incorrect code.';
    }
  })
  .catch(() => { msg.style.color='#dc2626'; msg.textContent='Network error.'; });
}

// Block step 1 → 2 until email verified
var _origKycNext = kycNext;
kycNext = function(step) {
  if (step === 1 && !_emailVerified) {
    var msg = document.getElementById('otp_msg');
    if (!document.getElementById('otp_row').style.display || document.getElementById('otp_row').style.display === 'none') {
      alert('Please verify your email address before continuing.');
    } else {
      msg.style.color = '#dc2626';
      msg.textContent = 'Please enter and verify the code sent to your email.';
    }
    return;
  }
  _origKycNext(step);
};

// ── If validation errors came back, jump to first error step ─
(function() {
  var hasError = document.querySelector('.has-error, .consent-item.has-error');
  if (!hasError) return;
  // Find which panel it's in
  for (var s = 1; s <= 5; s++) {
    var panel = document.getElementById('panel-' + s);
    if (panel && panel.querySelector('.has-error, [style*="display:block"]')) {
      kycGoto(s);
      break;
    }
  }
})();
